self.onmessage=async e=>{const{id:s,...t}=e.data;for(const e of Object.keys(t))self[e]=t[e];try{let e;if(s<0){const s=self.pyodide;importScripts(s);const t=s.replace(/\/[^/]*$/,"/");self.pyodide=await loadPyodide({indexURL:t}),await self.pyodide.loadPackage("micropip"),e=await self.pyodide.runPythonAsync("\n      import micropip\n      from js import packages, optlite\n      await micropip.install(optlite)\n      for p in packages:\n          await micropip.install(p)\n      ")}else await self.pyodide.loadPackagesFromImports(self.script),e=await self.pyodide.runPythonAsync("\n      import optlite\n      from js import script, rawInputLst\n      optlite.exec_script(script, rawInputLst)\n      ");self.postMessage({results:e,id:s})}catch(e){self.postMessage({error:"Failed to run code: "+e.message,id:s})}};